```c
#define _GNU_SOURCE
#include <sys/mman.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

#define HUGE_PAGE_SIZE (2 * 1024 * 1024) /* 2MB */
#define REGION_SIZE    (64 * HUGE_PAGE_SIZE) /* 128MB */

/*
 * Demonstrate THP control using madvise() for a
 * specific memory region.
 *
 * Requires: echo madvise > /sys/kernel/mm/transparent_hugepage/enabled
 */
int main(void)
{
    void *huge_region, *normal_region;
    size_t alignment = HUGE_PAGE_SIZE;

    /*
     * Allocate a 128MB region with THP enabled.
     * The address must be 2MB-aligned for THP.
     */
    huge_region = aligned_alloc(alignment, REGION_SIZE);
    if (!huge_region) {
        perror("aligned_alloc");
        return 1;
    }

    /*
     * MADV_HUGEPAGE: Tell the kernel to try using
     * transparent huge pages for this region.
     * The kernel will:
     * - Allocate 2MB compound pages for anonymous faults
     * - Run khugepaged to collapse existing 4KB pages
     */
    if (madvise(huge_region, REGION_SIZE, MADV_HUGEPAGE) < 0) {
        perror("madvise HUGEPAGE");
        free(huge_region);
        return 1;
    }

    /* Touch pages to trigger allocation */
    memset(huge_region, 'H', REGION_SIZE);

    printf("Huge region at %p (THP enabled)\n", huge_region);

    /*
     * Allocate a region with THP explicitly disabled.
     * Even if system-wide THP is 'always', MADV_NOHUGEPAGE
     * overrides it for this region.
     */
    normal_region = aligned_alloc(alignment, REGION_SIZE);
    if (!normal_region) {
        perror("aligned_alloc");
        free(huge_region);
        return 1;
    }

    /*
     * MADV_NOHUGEPAGE: Prevent THP for this region.
     * Useful for small, short-lived allocations where
     * the 2MB allocation overhead is not justified.
     */
    madvise(normal_region, REGION_SIZE, MADV_NOHUGEPAGE);

    memset(normal_region, 'N', REGION_SIZE);

    printf("Normal region at %p (THP disabled)\n", normal_region);

    /*
     * Verify THP usage by reading /proc/self/smaps.
     * The 'AnonHugePages' field shows THP-backed memory.
     */
    printf("\nChecking THP usage in /proc/self/smaps:\n");
    fflush(stdout);
    char cmd[256];
    snprintf(cmd, sizeof(cmd),
             "grep -A 15 '^[0-9a-f]' /proc/self/smaps | "
             "grep -E '(^%lx|^%lx|AnonHugePages|VmFlags)'",
             (unsigned long)huge_region,
             (unsigned long)normal_region);
    system(cmd);

    /*
     * MADV_COLLAPSE (since Linux 6.1): Force the kernel
     * to immediately collapse 4KB pages into a THP
     * synchronously, without waiting for khugepaged.
     */
#ifdef MADV_COLLAPSE
    if (madvise(huge_region, HUGE_PAGE_SIZE,
                MADV_COLLAPSE) == 0)
        printf("MADV_COLLAPSE succeeded for first 2MB\n");
#endif

    free(huge_region);
    free(normal_region);
    return 0;
}
```
madvise(MADV_HUGEPAGE) sets the VM_HUGEPAGE flag on the VMA, making it a priority target for THP allocation and khugepaged collapse. madvise(MADV_NOHUGEPAGE) sets VM_NOHUGEPAGE, preventing THP regardless of system settings. MADV_COLLAPSE (Linux 6.1+) provides synchronous THP promotion without relying on the background khugepaged thread.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * Parse /proc/pid/smaps to analyze per-VMA swap usage.
 * Each VMA section in smaps shows:
 *   - Virtual address range and permissions
 *   - Size, Rss, Pss, Shared/Private Clean/Dirty
 *   - Swap: amount swapped out for this VMA
 *   - SwapPss: proportional swap usage
 */

struct vma_swap_info {
    unsigned long start;
    unsigned long end;
    unsigned long size_kb;
    unsigned long rss_kb;
    unsigned long swap_kb;
    char perms[8];
    char mapping[256];
};

static void analyze_swap_usage(pid_t pid)
{
    char path[64];
    FILE *f;
    char line[512];
    struct vma_swap_info current;
    unsigned long total_swap = 0;
    int num_vmas_with_swap = 0;

    snprintf(path, sizeof(path), "/proc/%d/smaps", pid);
    f = fopen(path, "r");
    if (!f) {
        perror("open smaps");
        return;
    }

    memset(&current, 0, sizeof(current));

    while (fgets(line, sizeof(line), f)) {
        unsigned long start, end, size;
        char perms[8], mapping[256];

        /* Parse VMA header line */
        if (sscanf(line, "%lx-%lx %7s %*x %*s %*d %255[^\n]",
                   &start, &end, perms, mapping) >= 3) {
            /* Print previous VMA if it had swap */
            if (current.swap_kb > 0) {
                printf("  0x%lx-0x%lx %s swap=%luKB "
                       "(size=%luKB, rss=%luKB) %s\n",
                       current.start, current.end,
                       current.perms,
                       current.swap_kb,
                       current.size_kb,
                       current.rss_kb,
                       current.mapping);
                total_swap += current.swap_kb;
                num_vmas_with_swap++;
            }
            current.start = start;
            current.end = end;
            strncpy(current.perms, perms, sizeof(current.perms));
            strncpy(current.mapping, mapping[0] ? mapping : "(anon)",
                    sizeof(current.mapping));
            current.size_kb = current.rss_kb = current.swap_kb = 0;
        }
        /* Parse fields */
        else if (sscanf(line, "Size: %lu kB", &size) == 1)
            current.size_kb = size;
        else if (sscanf(line, "Rss: %lu kB", &size) == 1)
            current.rss_kb = size;
        else if (sscanf(line, "Swap: %lu kB", &size) == 1)
            current.swap_kb = size;
    }
    /* Print last VMA */
    if (current.swap_kb > 0) {
        printf("  0x%lx-0x%lx %s swap=%luKB "
               "(size=%luKB) %s\n",
               current.start, current.end,
               current.perms,
               current.swap_kb,
               current.size_kb,
               current.mapping);
        total_swap += current.swap_kb;
        num_vmas_with_swap++;
    }

    fclose(f);

    printf("\nSummary for PID %d:\n", pid);
    printf("  VMAs with swapped pages: %d\n", num_vmas_with_swap);
    printf("  Total swap used: %lu KB (%lu MB)\n",
           total_swap, total_swap / 1024);
}

int main(int argc, char *argv[])
{
    pid_t pid = argc > 1 ? atoi(argv[1]) : getpid();
    analyze_swap_usage(pid);
    return 0;
}
```
通过smaps可以精确定位哪些VMA（内存映射）的页面被换出到swap。这对于分析内存压力来源非常有用：如果匿名映射的swap量大，说明系统内存不足导致堆/栈数据被换出；如果共享内存段有swap，可能是tmpfs/shmem使用了swap空间。

Preemption control is intimately tied to locking in the Linux kernel. Each task has a preempt_count field — a 32-bit counter with sub-counters:

Bits 0-7: Preemption count. Bits 8-15: Softirq disable count. Bits 16-19: Hardirq count. Bit 20: NMI count.

Every lock acquisition increments preempt_count:
```c
static inline void spin_lock(spinlock_t *lock) {
    preempt_disable();
    raw_spin_lock(lock);
}
static inline void spin_unlock(spinlock_t *lock) {
    raw_spin_unlock(lock);
    preempt_enable();
}
```

preempt_enable() checks if preempt_count reaches zero and potentially calls the scheduler:
```c
static inline void preempt_enable(void) {
    barrier();
    if (unlikely(preempt_count_dec_and_test()))
        __preempt_schedule();
}
```

Common bugs:
```c
/* BUG: Sleeping with preemption disabled */
preempt_disable();
mutex_lock(&m); /* BUG: schedule() with preempt_count > 0 */

/* BUG: Forgetting preempt_enable on error path */
preempt_disable();
if (error) return -EIO; /* BUG: preempt_count still incremented */
preempt_enable();
```

might_sleep() annotation in many kernel functions triggers a warning if called with preempt_count > 0.

页表操作需要适当的锁保护以防止并发修改导致的数据损坏。Linux内核使用多层锁机制来保护页表。

**主要锁：**

1. **mmap_lock（原mmap_sem）：**
保护VMA列表和所有页表修改操作的顶层锁。
```c
// 读操作（查找VMA等）：共享锁
mmap_read_lock(mm);
vma = find_vma(mm, addr);
mmap_read_unlock(mm);

// 写操作（mmap, munmap, mprotect）：排他锁
mmap_write_lock(mm);
// 修改VMA列表和页表
mmap_write_unlock(mm);
```

2. **page_table_lock：**
保护页表页面本身的修改（PTE设置/清除）。
```c
// 在修改PTE时
spin_lock(&mm->page_table_lock);
set_pte_at(mm, addr, pte, entry);
spin_unlock(&mm->page_table_lock);
```
大多数架构使用split page table lock（每页表页面一个锁）来减少竞争。

3. **Split page table lock：**
```c
// 每个PTE页面有自己的锁
static inline spinlock_t *pte_lockptr(struct mm_struct *mm, pte_t *pte)
{
    // 锁存储在struct page中
    return ptlock_ptr(virt_to_page(pte));
}

// 使用方式
ptl = pte_lockptr(mm, pte);
spin_lock(ptl);
// 修改PTE
spin_unlock(ptl);
```

4. **PMD/PUD锁：**
类似PTE，每个PMD/PUD页面有独立的锁。

**锁层次：**
```
mmap_lock (rw_semaphore)
  └── page_table_lock / split ptlock (spinlock)
        └── zone->lock (spinlock, for buddy allocator)
```

**无锁操作：**
某些操作是天然无锁的：
- 设置PTE从not-present到present（原子写入）
- 读取PTE（单次读取）
- cmpxchg用于原子PTE修改

**TLB一致性：**
页表修改后的TLB刷新需要额外的同步：
- 本地刷新：在修改PTE的同一CPU上执行
- 远程刷新：通过IPI（TLB shootdown）在其他CPU上执行
- mmu_gather用于批量操作，减少TLB刷新次数

`pidfd_open()` (Linux 5.3) creates a file descriptor referring to a process, enabling race-free process management. Implementation is in `kernel/pid.c` and `kernel/fork.c`.

**System call**:
```c
SYSCALL_DEFINE2(pidfd_open, pid_t, pid, unsigned int, flags) {
    struct pid *p;
    int fd;
    p = find_get_pid(pid);
    if (!p) return -ESRCH;
    fd = pidfd_create(p, flags);
    put_pid(p);
    return fd;
}
```

**pidfd_create()**: Creates a file descriptor backed by the `struct pid`:
```c
static int pidfd_create(struct pid *pid, unsigned int flags) {
    int fd = anon_inode_getfd("[pidfd]", &pidfd_fops, pid, flags | O_RDWR | O_CLOEXEC);
    get_pid(pid);
    return fd;
}
```

**Use cases**:
1. **Race-free signal delivery**: `pidfd_send_signal(pidfd, sig, info, flags)` sends a signal to the process identified by the pidfd, avoiding PID reuse races.
2. **Pollable process exit**: `poll()` / `epoll()` on a pidfd returns readable when the process exits.
3. **Process monitoring**: Use pidfd with `waitid(P_PIDFD, ...)` for process exit notification.

**File operations** (`pidfd_fops` in `kernel/fork.c`):
- `pidfd_release()`: Releases the pid reference on close
- `pidfd_poll()`: Returns POLLIN when the process has exited (`thread_group_empty()` and zombie state)
- `pidfd_show_fdinfo()`: Shows pid information in `/proc/[pid]/fdinfo/`

**Relationship with clone3()**: `clone3()` with `CLONE_PIDFD` returns a pidfd for the child instead of a PID, combining process creation and pidfd creation atomically.

**Advantages over PIDs**:
- PID reuse: PIDs are recycled, so PID 42 might refer to a different process later. Pidfds are unique.
- Race conditions: Between `kill(pid, 0)` checking existence and `kill(pid, SIGKILL)`, the process might exit and the PID be reused.
- Namespace awareness: Pidfds work across PID namespaces transparently.

The brk() system call adjusts the program break, which defines the end of the process's data segment (heap). It's the traditional mechanism for heap allocation (used by malloc internally).

**brk() implementation:**
```c
// mm/mmap.c
SYSCALL_DEFINE1(brk, unsigned long, brk)
{
    struct mm_struct *mm = current->mm;
    unsigned long retval;
    unsigned long newbrk, oldbrk;

    mmap_write_lock(mm);

    // Current break
    oldbrk = mm->brk;

    // Requested new break (page-aligned)
    newbrk = PAGE_ALIGN(brk);

    // If shrinking the heap
    if (newbrk < oldbrk) {
        // Unmap the released pages
        do_munmap(mm, newbrk, oldbrk - newbrk);
        mm->brk = brk;
        goto out;
    }

    // If growing the heap
    // Check against mmap region and stack
    if (newbrk >= mm->start_brk + rlimit(RLIMIT_DATA))
        goto out;  // Exceeds data segment limit

    // Check for overlap with mmap region
    if (!may_expand_vm(mm, (newbrk - oldbrk) >> PAGE_SHIFT))
        goto out;

    // Expand the VMA or create new mapping
    do_brk_flags(oldbrk, newbrk - oldbrk, 0);
    mm->brk = brk;

out:
    retval = mm->brk;
    mmap_write_unlock(mm);
    return retval;
}
```

**Heap VMA:**
The heap is represented by a single VMA with vm_start = start_brk and vm_end = brk (page-aligned):
```c
// The heap VMA grows upward
// vm_flags: VM_READ | VM_WRITE | VM_MAYREAD | VM_MAYWRITE | VM_GROWSDOWN?
// No, heap uses VM_GROWSUP or just explicit brk expansion
```

**brk vs mmap for heap:**
Modern malloc implementations (glibc) use:
- brk() for small allocations (< MMAP_THRESHOLD, default 128KB)
- mmap(MAP_ANONYMOUS) for large allocations
This allows large blocks to be returned to the OS immediately via munmap(), while brk-allocated memory can only be released by shrinking the break.

**mmap-based heap (THP-aware):**
Recent kernels support using mmap for the heap with THP support:
```c
// In do_brk_flags()
if (IS_ENABLED(CONFIG_TRANSPARENT_HUGE_PAGECACHE))
    flags |= VM_HUGEPAGE;  // Allow THP for heap
```

Using the dmaengine API for async memory-to-peripheral transfers:

```c
#include <linux/dmaengine.h>
#include <linux/dma-mapping.h>

struct dma_xfer_ctx {
    struct dma_chan *chan;
    struct completion done;
    void *src_buf;
    dma_addr_t src_dma;
    size_t len;
};

static void dma_complete(void *data) {
    struct dma_xfer_ctx *ctx = data;
    complete(&ctx->done);
}

static int dma_transfer_to_peripheral(struct device *dev,
                                       struct dma_xfer_ctx *ctx,
                                       dma_addr_t dst_addr) {
    struct dma_async_tx_descriptor *desc;
    enum dma_transfer_direction dir = DMA_MEM_TO_DEV;
    dma_cookie_t cookie;

    /* Request a DMA channel matching the slave device */
    if (!ctx->chan) {
        dma_cap_mask_t mask;
        dma_cap_zero(mask);
        dma_cap_set(DMA_SLAVE, mask);
        ctx->chan = dma_request_chan_by_mask(mask);
        if (IS_ERR(ctx->chan)) return PTR_ERR(ctx->chan);
    }

    /* Map source buffer for DMA */
    ctx->src_dma = dma_map_single(dev, ctx->src_buf, ctx->len, DMA_TO_DEVICE);
    if (dma_mapping_error(dev, ctx->src_dma))
        return -ENOMEM;

    /* Prepare slave transfer descriptor */
    struct dma_slave_config cfg = {
        .direction = dir,
        .dst_addr = dst_addr,
        .dst_addr_width = DMA_SLAVE_BUSWIDTH_4_BYTES,
        .dst_maxburst = 16,
    };
    dmaengine_slave_config(ctx->chan, &cfg);

    desc = dmaengine_prep_slave_single(ctx->chan, ctx->src_dma, ctx->len,
                                        dir, DMA_PREP_INTERRUPT | DMA_CTRL_ACK);
    if (!desc) {
        dma_unmap_single(dev, ctx->src_dma, ctx->len, DMA_TO_DEVICE);
        return -ENOMEM;
    }

    /* Set completion callback */
    init_completion(&ctx->done);
    desc->callback = dma_complete;
    desc->callback_param = ctx;

    /* Submit and issue */
    cookie = dmaengine_submit(desc);
    if (dma_submit_error(cookie))
        return cookie;

    dma_async_issue_pending(ctx->chan);

    /* Wait for completion */
    if (!wait_for_completion_timeout(&ctx->done, msecs_to_jiffies(5000))) {
        dmaengine_terminate_sync(ctx->chan);
        return -ETIMEDOUT;
    }

    dma_unmap_single(dev, ctx->src_dma, ctx->len, DMA_TO_DEVICE);
    return 0;
}

static void dma_cleanup(struct dma_xfer_ctx *ctx) {
    if (ctx->chan) {
        dmaengine_terminate_sync(ctx->chan);
        dma_release_channel(ctx->chan);
        ctx->chan = NULL;
    }
}
```

`dma_request_chan_by_mask()` finds a channel matching capability requirements. `dmaengine_slave_config()` programs channel-specific parameters like burst size and address width. `DMA_PREP_INTERRUPT` requests a completion callback. `dma_async_issue_pending()` starts the queued transfer. `dmaengine_terminate_sync()` aborts in-flight transfers and waits for the callback to finish — essential during error paths and module removal.

