```c
#define _GNU_SOURCE
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <stdlib.h>
#include <string.h>

/*
 * fincore() determines which pages of a file are
 * currently resident in the page cache.
 *
 * The vec array receives one byte per page:
 *   bit 0 (FINCORE_PRESENT): page is in cache
 *   bit 1 (FINCORE_DIRTY): page is dirty
 *   (other bits reserved)
 *
 * Available since Linux 4.14.
 */

#ifndef SYS_fincore
#define SYS_fincore 327  /* x86_64 syscall number */
#endif

static int my_fincore(int fd, void *start, size_t len,
                       unsigned char *vec)
{
    return syscall(SYS_fincore, fd, start, len, vec);
}

static void analyze_file_cache(const char *path)
{
    int fd;
    struct stat st;
    void *map;
    unsigned char *vec;
    size_t num_pages;
    size_t pages_in_cache = 0;
    size_t dirty_pages = 0;
    size_t i;

    fd = open(path, O_RDONLY);
    if (fd < 0) { perror("open"); return; }

    fstat(fd, &st);
    num_pages = (st.st_size + 4095) / 4096;

    /*
     * mmap the file to get a virtual address range.
     * fincore requires the file to be mmapped.
     */
    map = mmap(NULL, st.st_size, PROT_NONE,
               MAP_PRIVATE, fd, 0);
    if (map == MAP_FAILED) {
        perror("mmap");
        close(fd);
        return;
    }

    vec = calloc(num_pages, 1);
    if (!vec) {
        munmap(map, st.st_size);
        close(fd);
        return;
    }

    /*
     * Call fincore to check page cache status.
     * Kernel path: do_fincore() walks the file's
     * address_space xarray, checking each page index.
     */
    if (my_fincore(fd, map, st.st_size, vec) < 0) {
        perror("fincore");
    } else {
        for (i = 0; i < num_pages; i++) {
            if (vec[i] & 1) {  /* FINCORE_PRESENT */
                pages_in_cache++;
                if (vec[i] & 2)  /* FINCORE_DIRTY */
                    dirty_pages++;
            }
        }

        printf("File: %s (%zu bytes, %zu pages)\n",
               path, (size_t)st.st_size, num_pages);
        printf("Pages in cache: %zu/%zu (%.1f%%)\n",
               pages_in_cache, num_pages,
               100.0 * pages_in_cache / num_pages);
        printf("Dirty pages: %zu\n", dirty_pages);

        /*
         * Alternative: use mincore() for mmap'd files:
         * mincore(map, st.st_size, vec);
         * mincore checks if pages are resident for the
         * specific mapping (works for all mmap'd files).
         */
    }

    free(vec);
    munmap(map, st.st_size);
    close(fd);
}

int main(int argc, char *argv[])
{
    if (argc < 2) {
        printf("Usage: %s <file>\n", argv[0]);
        return 1;
    }
    analyze_file_cache(argv[1]);
    return 0;
}
```
fincore() provides a zero-copy way to check page cache status without actually reading the file. It's useful for: (1) Database buffer managers deciding which pages to prefetch; (2) Backup tools identifying dirty pages for incremental backup; (3) Monitoring tools tracking cache hit rates per file.

```c
#define _GNU_SOURCE
#include <sched.h>
#include <sys/syscall.h>
#include <linux/types.h>
#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>

/* clone3的系统调用号和结构体（来自linux/sched.h） */
struct clone_args {
    __aligned_u64 flags;       /* CLONE_* 标志 */
    __aligned_u64 pidfd;       /* 输出: pidfd文件描述符 */
    __aligned_u64 child_tid;   /* 子线程的TID地址 */
    __aligned_u64 parent_tid;  /* 父线程的TID地址 */
    __aligned_u64 exit_signal; /* 子进程退出时发送的信号 */
    __aligned_u64 stack;       /* 子进程栈地址 */
    __aligned_u64 stack_size;  /* 栈大小 */
    __aligned_u64 tls;         /* TLS描述符 */
    __aligned_u64 set_tid;     /* 指定PID（需要权限） */
    __aligned_u64 set_tid_size;/* set_tid数组大小 */
    __aligned_u64 cgroup;      /* cgroup文件描述符 */
};

#ifndef __NR_clone3
#define __NR_clone3 435
#endif

int main(void) {
    struct clone_args args = {0};
    int pidfd = -1;

    args.flags = CLONE_NEWPID | CLONE_NEWNS;
    args.pidfd = (__aligned_u64)&pidfd;  /* 获取pidfd */
    args.exit_signal = SIGCHLD;

    pid_t pid = syscall(__NR_clone3, &args, sizeof(args));
    if (pid < 0) {
        perror("clone3");
        return 1;
    }

    if (pid == 0) {
        /* 子进程: 新PID命名空间中的PID 1 */
        printf("Child PID: %d\n", getpid());
        sleep(5);
        _exit(0);
    }

    /* 父进程: pidfd可用于pidfd_send_signal()和poll() */
    printf("Parent: child PID=%d, pidfd=%d\n", pid, pidfd);

    /* 使用pidfd_wait（无需waitpid的race-free等待） */
    /* pidfd_send_signal(pidfd, SIGTERM, NULL, 0); */

    close(pidfd);
    return 0;
}
```

clone3()（kernel/fork.c）是clone()的现代替代，支持pidfd输出、指定PID（set_tid）、cgroup v2目标cgroup等功能。set_tid允许在指定PID命名空间中设置精确的PID号。

bpftrace can monitor per-container resource usage using cgroup-based filtering to detect noisy neighbor problems: (1) CPU usage by cgroup:
```bash
bpftrace -e '
profile:hz:99 /cgroup == "docker-abc123"/ {
    @["container_cpu"] = count();
}
profile:hz:99 /cgroup != "docker-abc123"/ {
    @["other_cpu"] = count();
}
interval:s:5 { print(@); clear(@); }
'
```
(2) I/O by cgroup:
```bash
bpftrace -e '
tracepoint:block:block_io_start /cgroup == $1/ {
    @io_bytes[comm] = sum(args->bytes);
    @io_count[comm] = count();
}
' $(cat /sys/fs/cgroup/docker/container_id/cgroup.id)
```
(3) Network by cgroup:
```bash
bpftrace -e '
kprobe:tcp_sendmsg /cgroup == $1/ {
    @net_send = sum(arg2);  /* size argument */
}
kretprobe:tcp_recvmsg /cgroup == $1/ {
    @net_recv = sum(retval);
}
'
```
(4) Memory pressure:
```bash
bpftrace -e '
tracepoint:kmem:mm_page_alloc /cgroup == $1/ {
    @page_allocs = count();
}
tracepoint:vmscan:mm_vmscan_direct_reclaim_begin /cgroup == $1/ {
    @direct_reclaim = count();
}
'
```
(5) Noisy neighbor detection: Combine all metrics and compare against baselines. A container causing high direct_reclaim on other containers, or consuming disproportionate CPU/IO, is a noisy neighbor. Use cgroup-aware BPF programs for production monitoring with lower overhead than bpftrace.

```c
#define _GNU_SOURCE
#include <sched.h>
#include <linux/types.h>
#include <sys/syscall.h>
#include <unistd.h>

struct sched_attr {
    __u32 size;
    __u32 sched_policy;
    __u64 sched_flags;
    __s32 sched_nice;
    __u32 sched_priority;
    __u64 sched_runtime;   /* nanoseconds */
    __u64 sched_deadline;  /* nanoseconds */
    __u64 sched_period;    /* nanoseconds */
};

int sched_setattr(pid_t pid, const struct sched_attr *attr,
                  unsigned int flags)
{
    return syscall(__NR_sched_setattr, pid, attr, flags);
}

int main(void) {
    struct sched_attr attr = {
        .size = sizeof(attr),
        .sched_policy = SCHED_DEADLINE,
        .sched_runtime  =  5 * 1000 * 1000,  /* 5ms */
        .sched_deadline = 10 * 1000 * 1000,  /* 10ms */
        .sched_period   = 20 * 1000 * 1000,  /* 20ms */
    };
    /* CBS: runtime=5ms, deadline=10ms, period=20ms */
    /* Bandwidth = runtime/period = 25% */
    if (sched_setattr(0, &attr, 0) < 0) {
        perror("sched_setattr"); /* EPERM, EBUSY */
        return 1;
    }
    /* Task now runs under EDF with CBS enforcement */
    while (1) { /* periodic task body */ }
}
```

The sched_setattr() syscall (kernel/sched/core.c) performs admission control: it checks that the new task's bandwidth plus existing DL bandwidth doesn't exceed the CPU's capacity (sysctl_sched_dl_period_max). Failure returns EBUSY. Requires CAP_SYS_NICE.

Wait queues are a fundamental mechanism in the Linux kernel for putting processes to sleep while waiting for a condition to become true. They are defined in `include/linux/wait.h` and implemented in `kernel/sched/wait.c`.

**Data structures**:
- `wait_queue_head_t` (alias for `struct wait_queue_head`): Contains a spinlock and a doubly-linked list of waiters:
```c
struct wait_queue_head {
    spinlock_t lock;
    struct list_head head;
};
```
- `wait_queue_entry_t` (alias for `struct wait_queue_entry`): Represents a waiter, containing a pointer to the task, flags (exclusive/wakeup), and a callback function:
```c
struct wait_queue_entry {
    unsigned int flags;
    struct task_struct *private;
    wait_queue_func_t func;
    struct list_head entry;
};
```

**Declaration and initialization**:
- Static: `DECLARE_WAIT_QUEUE_HEAD(name);`
- Dynamic: `init_waitqueue_head(&wq_head);`

**Sleeping (waiting)**:
- `wait_event(wq, condition)`: Uninterruptible sleep until condition is true
- `wait_event_interruptible(wq, condition)`: Interruptible sleep, returns -ERESTARTSYS if a signal arrives
- `wait_event_timeout(wq, condition, timeout)`: With a timeout
- `wait_event_interruptible_timeout(wq, condition, timeout)`: Both interruptible and with timeout

Internally, these macros expand to `___wait_event()` which uses `prepare_to_wait_event()` to add the current task to the wait queue, set its state, and call `schedule()`.

**Waking up**:
- `wake_up(&wq)`: Wakes all non-exclusive waiters and one exclusive waiter
- `wake_up_interruptible(&wq)`: Same but only for interruptible waiters
- `wake_up_nr(&wq, nr)`: Wakes up to `nr` exclusive waiters
- `wake_up_all(&wq)`: Wakes all waiters including all exclusive ones

These call `__wake_up()` which iterates the wait queue list and invokes each entry's callback function (typically `autoremove_wake_function()` which calls `try_to_wake_up()` and removes the entry).

**Exclusive waiters** prevent the thundering herd problem: when many processes wait for the same resource, only one is woken at a time.

**Example usage** in device drivers:
```c
DECLARE_WAIT_QUEUE_HEAD(my_wq);
int data_ready = 0;

// Producer
void data_arrived(void) {
    data_ready = 1;
    wake_up_interruptible(&my_wq);
}

// Consumer
ssize_t my_read(...) {
    if (wait_event_interruptible(my_wq, data_ready))
        return -ERESTARTSYS;
    // process data
}
```

The kernel collects extensive statistics (network packets, disk I/O, scheduling events) that must be updated from multiple CPUs concurrently. Lock-free approaches are essential for performance.

**Per-CPU counters**:
```c
#include <linux/percpu_counter.h>

struct percpu_counter {
    raw_spinlock_t lock;        /* Only for slow path */
    s64 count;                  /* Global sum (approximate) */
    s32 __percpu *counters;     /* Per-CPU local counts */
};

/* Fast path: update per-CPU counter — lock-free */
static inline void percpu_counter_add(struct percpu_counter *fbc, s64 amount) {
    s32 *pcount = this_cpu_ptr(fbc->counters);
    s32 count = *pcount + amount;
    /* If local count exceeds batch, flush to global */
    if (abs(count) >= percpu_counter_batch) {
        raw_spin_lock(&fbc->lock);
        fbc->count += count;
        raw_spin_unlock(&fbc->lock);
        count = 0;
    }
    *pcount = count;
}

/* Read: approximate — no lock, iterates all CPUs */
s64 percpu_counter_read(struct percpu_counter *fbc) {
    return fbc->count;  /* Approximate — doesn't include per-CPU locals */
}

/* Read exact: iterates all CPUs with lock */
s64 percpu_counter_sum(struct percpu_counter *fbc) {
    s64 ret = fbc->count;
    int cpu;
    for_each_possible_cpu(cpu)
        ret += *per_cpu_ptr(fbc->counters, cpu);
    return ret;  /* Still approximate — CPUs may change during iteration */
}
```

**This-CPU statistics** (zero-lock):
```c
/* Network device statistics — completely lock-free */
struct rtnl_link_stats64 {
    u64 rx_packets, tx_packets;
    u64 rx_bytes, tx_bytes;
    /* ... */
};

static DEFINE_PER_CPU(struct rtnl_link_stats64, dev_stats);

/* TX path — one CPU increments */
void record_tx(int bytes) {
    this_cpu_inc(dev_stats.tx_packets);
    this_cpu_add(dev_stats.tx_bytes, bytes);
}

/* Stats aggregation — reads all CPUs */
void get_stats(struct rtnl_link_stats64 *out) {
    int cpu;
    for_each_possible_cpu(cpu) {
        struct rtnl_link_stats64 *s = per_cpu_ptr(&dev_stats, cpu);
        out->tx_packets += s->tx_packets;
        out->tx_bytes += s->tx_bytes;
    }
}
```

**Key principles**: (1) Per-CPU updates: zero-lock, zero-cache-bounce. (2) Batched global updates: amortize lock cost. (3) Approximate reads: acceptable for statistics. (4) this_cpu_* ops: single instruction, safe with preemption.

```c
#include <linux/wait.h>

/* Exclusive waiters: only one is woken per wake_up call */
/* This prevents thundering herd when many tasks wait on same event */

static wait_queue_head_t resource_wq;
static atomic_t resource_available = ATOMIC_INIT(1);

int acquire_resource_exclusive(void)
{
    DEFINE_WAIT_FUNC(wait, woken_wake_function);
    /* woken_wake_function + WQ_FLAG_EXCLUSIVE ensures only
       one waiter is woken per wake_up() */

    add_wait_queue_exclusive(&resource_wq, &wait);
    /* _exclusive variant sets WQ_FLAG_EXCLUSIVE automatically */

    for (;;) {
        if (!atomic_read(&resource_available)) {
            set_current_state(TASK_INTERRUPTIBLE);
            if (!atomic_read(&resource_available))
                schedule();  /* Sleep until woken */
        }

        /* Try to acquire */
        if (atomic_dec_and_test(&resource_available)) {
            /* Got the resource */
            break;
        }
        /* Lost race — go back to sleep */
        set_current_state(TASK_INTERRUPTIBLE);
    }

    __set_current_state(TASK_RUNNING);
    remove_wait_queue(&resource_wq, &wait);
    return 0;
}

void release_resource(void)
{
    atomic_set(&resource_available, 1);
    /* wake_up() (not wake_up_all) wakes only first exclusive waiter */
    wake_up(&resource_wq);
}
```

prepare_to_wait_event() in kernel/sched/wait.c handles the exclusive/non-exclusive distinction. Exclusive waiters are added to the tail of the queue, non-exclusive to the head. wake_up() stops after waking the first exclusive waiter, preventing thundering herd.

Double-free is a serious memory corruption bug where the same memory is freed twice. The kernel has several mechanisms to detect this.

**Basic detection in SLUB:**
When an object is freed, its freelist pointer is set. A double-free would write the freelist pointer again, corrupting the freelist chain. SLUB detects this via:

```c
static inline void set_freepointer(struct kmem_cache *s, void *object, void *fp)
{
    unsigned long freeptr_addr = (unsigned long)object + s->offset;
    // With debugging enabled, check for double-free
    BUG_ON(object == fp);  // Object pointing to itself = double free
    *(void **)(freeptr_addr) = fp;
}
```

**SLUB debug double-free detection:**
```c
// With slub_debug=F (sanity checks)
static void check_object(struct kmem_cache *s, struct page *page,
                          void *object, u8 val)
{
    // Check if the object's freelist pointer is valid
    void *freepointer = get_freepointer(s, object);

    // If the object is already on the freelist, freepointer
    // will be non-NULL — detecting double free
    if (val == SLUB_RED_INACTIVE && freepointer)
        object_err(s, page, object, "Double free detected");
}
```

**KASAN (Kernel Address SANitizer):**
KASAN provides the most robust double-free detection:
```c
// When kfree() is called:
void kasan_kfree_large(void *ptr, unsigned long ip)
{
    // Check shadow memory — if already freed, shadow shows "freed"
    if (kasan_check_range(ptr, size, false, ip))
        // Report: double-free detected at this call site
        kasan_report_double_free(ptr, ip);
}
```

KASAN marks freed memory as "freed" in shadow memory. Any subsequent kfree() on the same address triggers a detailed report with allocation and free stack traces.

**Consequences of undetected double-free:**
1. Freelist corruption — subsequent allocations return the same object twice
2. Use-after-free — one caller modifies data that another caller sees
3. Potential privilege escalation in kernel context

Module signature verification is controlled by CONFIG_MODULE_SIG. When enabled, each module has a PKCS#7 signature appended after the ELF payload. The signature covers the module's SHA-256 hash and includes the signer's certificate chain. At load time, mod_verify_sig() in kernel/module/signing.c extracts the signature, verifies the certificate chain against trusted keys in the .builtin_trusted_keys and .secondary_trusted_keys keyrings. The kernel's built-in keyring contains the key compiled into the kernel (generated during build if CONFIG_MODULE_SIG_KEY is set). The secondary keyring can be populated at runtime via keyctl. If CONFIG_MODULE_SIG_FORCE is set, all modules must have valid signatures. Under lockdown, unsigned modules are always rejected. The signature includes the module's hash, signer name, key ID, and timestamp. Tools like scripts/sign-file and pesign handle signing during kernel package build. The modinfo command displays signature information with 'modinfo -F sig_hashalgo module.ko'. BPF program attached to a kprobe for tracing:
```c
/* tools/bpf/bpftool example - BPF C program */
#include <linux/bpf.h>
#include <bpf/bpf_helpers.h>
#include <bpf/bpf_tracing.h>

struct {
    __uint(type, BPF_MAP_TYPE_HASH);
    __uint(max_entries, 1024);
    __type(key, __u32);
    __type(value, __u64);
} call_counts SEC(".maps");

SEC("kprobe/do_sys_openat2")
int trace_open(struct pt_regs *ctx)
{
    __u32 pid = bpf_get_current_pid_tgid() >> 32;
    __u64 *count;

    count = bpf_map_lookup_elem(&call_counts, &pid);
    if (count)
        __sync_fetch_and_add(count, 1);
    else {
        __u64 init = 1;
        bpf_map_update_elem(&call_counts, &pid, &init, BPF_ANY);
    }
    return 0;
}

char LICENSE[] SEC("license") = "GPL";
```

```c
#include <linux/mm.h>
#include <linux/page_owner.h>

/*
 * Page owner tracking records the allocation call stack
 * for every page allocated by the buddy allocator.
 * Enabled via: page_owner=on boot parameter or
 * CONFIG_PAGE_OWNER + CONFIG_PAGE_OWNER_FILTERED.
 *
 * Usage: /sys/kernel/debug/page_owner shows allocation
 * stacks for all allocated pages.
 */

/*
 * Dump page owner information for a specific page.
 */
static void dump_page_owner(struct page *page)
{
    struct page_owner *page_owner;
    depot_stack_handle_t handle;
    unsigned long *entries;
    unsigned int nr_entries;

    if (!page_owner) {
        pr_info("Page owner tracking not enabled\n");
        return;
    }

    page_owner = get_page_owner(page);
    if (!page_owner) {
        pr_info("No owner info for page pfn=%lu\n",
                page_to_pfn(page));
        return;
    }

    pr_info("Page pfn=%lu owner info:\n", page_to_pfn(page));
    pr_info("  Order: %d\n", page_owner->order);
    pr_info("  Migratetype: %d\n", page_owner->mt);
    pr_info("  GFP mask: 0x%x\n", page_owner->gfp_mask);
    pr_info("  PID: %d\n", page_owner->pid);
    pr_info("  Timestamp: %llu ns\n", page_owner->ts_nsec);

    /*
     * Decode the stack trace.
     * The stack is stored as a depot_stack_handle_t
     * (compressed stack trace ID).
     */
    handle = page_owner->handle;
    nr_entries = stack_depot_fetch(handle, &entries);

    pr_info("  Allocation stack trace (%u frames):\n",
            nr_entries);
    for (unsigned int i = 0; i < nr_entries; i++) {
        char name[KSYM_NAME_LEN];
        sprint_symbol(name, entries[i]);
        pr_info("    [%u] 0x%lx %s\n",
                i, entries[i], name);
    }
}

/*
 * Find all pages allocated by a specific function.
 * This is useful for tracking memory leaks.
 */
static void find_pages_by_caller(unsigned long caller_addr)
{
    unsigned long pfn;
    struct page *page;

    for (pfn = 0; pfn < max_pfn; pfn++) {
        if (!pfn_valid(pfn))
            continue;
        page = pfn_to_page(pfn);
        if (!PageBuddy(page) && page_count(page) > 0) {
            struct page_owner *po = get_page_owner(page);
            if (po && po->pid > 0) {
                /* Check if caller is in the stack */
                /* (simplified — real code would decode
                 * the depot handle) */
            }
        }
    }
}
```
page_owner是一个强大的内存调试工具。当检测到内存泄漏时，可以通过/proc/page_owner或dmesg中的dump_page_owner输出来追踪泄漏页面的分配调用栈。它记录的信息包括：分配时的进程PID、GFP标志、order和migratetype，以及完整的内核栈跟踪。

```c
#include <linux/slab.h>
#include <linux/debugfs.h>

/*
 * Demonstrate SLUB cache statistics monitoring.
 * SLUB provides extensive statistics through
 * /sys/kernel/slab/<cache>/ directory.
 */

struct my_data {
    u64 timestamp;
    u32 value;
    char label[16];
};

static struct kmem_cache *my_cache;

static void print_cache_stats(void)
{
    /*
     * Key files in /sys/kernel/slab/<cache_name>/:
     *
     * object_size: size of each object (including metadata)
     * objects: total number of allocated objects
     * slabs: number of slab pages
     * total_objects: total object slots (slabs * objects_per_slab)
     * cpu_slabs: per-CPU slab count
     * partial: number of slabs in partial list
     * objects_partial: free objects in partial slabs
     *
     * With slub_debug enabled:
     * trace: enable allocation tracing
     * validate: trigger slab validation
     * sanity_checks: enable sanity checks
     */

    /* In kernel code, use sysfs interfaces or direct
     * access to kmem_cache internals: */
    struct kmem_cache_node *n;
    int node;

    pr_info("Cache: %s\n", my_cache->name);
    pr_info("  Object size: %u\n", my_cache->object_size);
    pr_info("  Inuse size: %u\n", my_cache->inuse);
    pr_info("  Align: %u\n", my_cache->align);
    pr_info("  Object size (with metadata): %u\n",
            my_cache->size);

    for_each_node(node) {
        n = get_node(my_cache, node);
        if (!n)
            continue;
        pr_info("  Node %d: nr_partial=%lu nr_slabs=%lu\n",
                node, n->nr_partial,
                atomic_long_read(&n->nr_slabs));
    }
}

/*
 * Enable SLUB debugging for a specific cache:
 * Boot parameter: slub_debug=FZPU,name=my_cache
 *   F = redzone (detect overflows)
 *   Z = poison (detect use-after-free)
 *   P = sanity checks
 *   U = tracing
 */
static int __init my_module_init(void)
{
    my_cache = kmem_cache_create("my_data",
                                  sizeof(struct my_data),
                                  0,
                                  SLAB_RED_ZONE | SLAB_POISON,
                                  NULL);
    if (!my_cache)
        return -ENOMEM;

    print_cache_stats();
    return 0;
}
```
SLUB的调试功能通过slub_debug内核参数控制。F（redzone）检测缓冲区溢出，Z（poison）检测use-after-free，P（sanity checks）验证slab内部一致性。这些功能在开发和测试阶段非常有用，但在生产环境中会增加性能开销。

```c
#include <unistd.h>
#include <sys/wait.h>
#include <signal.h>
#include <termios.h>
#include <sys/ioctl.h>

/* Simple shell job control: run a pipeline in foreground */
void run_pipeline_foreground(char *argv[], int argc, pid_t shell_pgid)
{
    pid_t pgid = -1;
    int i;

    for (i = 0; i < argc; i++) {
        pid_t pid = fork();
        if (pid == 0) {
            /* Child process */
            if (pgid == -1)
                pgid = getpid(); /* First process is PG leader */

            /* Join the pipeline's process group */
            setpgid(getpid(), pgid);

            /* If first process, give terminal control */
            if (i == 0)
                tcsetpgrp(STDIN_FILENO, pgid);

            /* Restore default signal dispositions */
            signal(SIGINT, SIG_DFL);
            signal(SIGTSTP, SIG_DFL);
            signal(SIGTTIN, SIG_DFL);
            signal(SIGTTOU, SIG_DFL);

            /* Set up pipes (simplified) */
            if (i < argc - 1) {
                /* Connect stdout to pipe */
            }
            if (i > 0) {
                /* Connect stdin from pipe */
            }

            execvp(argv[i], &argv[i]);
            _exit(127);
        }

        /* Parent: set child's PGID (race-free with child) */
        if (pgid == -1)
            pgid = pid;
        setpgid(pid, pgid);
    }

    /* Wait for foreground pipeline to complete */
    int status;
    while (waitpid(-pgid, &status, WUNTRACED) > 0) {
        if (WIFSTOPPED(status)) {
            /* Pipeline stopped (SIGTSTP/SIGTTIN) — background it */
            fprintf(stderr, "[%d]+ Stopped\n", pgid);
            break;
        }
        if (WIFEXITED(status) || WIFSIGNALED(status))
            break;
    }

    /* Reclaim terminal control */
    tcsetpgrp(STDIN_FILENO, shell_pgid);
}
```

WUNTRACED flag reports stopped children (job control). The shell tracks jobs in its own job table, using PGID as the job identifier.

