The relationship between `thread_info`, `task_struct`, and the kernel stack has evolved significantly across kernel versions.

**Historical approach (pre-4.9)**: On most architectures, the kernel stack and `thread_info` were combined in a single allocation called `thread_union`:
```c
union thread_union {
    struct thread_info thread_info;
    unsigned long stack[THREAD_SIZE / sizeof(long)];
};
```
The `thread_info` was placed at the bottom (low address) of the stack allocation. The `current` macro obtained the current process by masking the stack pointer to find `thread_info`, which contained a pointer to `task_struct`. This was efficient but limited the information that could fit.

**Modern approach (4.9+, CONFIG_THREAD_INFO_IN_TASK)**: The `thread_info` structure was moved inside `task_struct` itself. The `current` macro now uses per-CPU variables instead of stack-pointer masking. On x86-64, the `gs` segment register points to a per-CPU area containing `current_task`. On ARM64, the `sp_el0` system register stores the current task pointer.

The kernel stack itself is typically allocated as two pages (8KB on x86_64 with `CONFIG_8K_STACKS`, or one page with `CONFIG_VMAP_STACK` since 4.9). With `CONFIG_VMAP_STACK`, stacks are allocated in the vmalloc area with guard pages to detect stack overflows, triggering a double-fault or stack-overflow exception.

The `task_struct` is allocated separately via `kmem_cache_alloc()` from the `task_struct_cachep` slab cache. The `stack` field in `task_struct` points to the kernel stack. The thread-local data previously in `thread_info` (like `preempt_count`, `addr_limit`) is now in `task_struct::thread_info` or in the `thread_struct` embedded in `task_struct`.

This evolution improved security (stack guard pages), reliability (stack overflow detection), and code clarity.

以下是一个简化的优先级继承互斥锁实现框架，展示核心PI协议逻辑。

```c
#include <linux/spinlock.h>
#include <linux/sched.h>
#include <linux/rbtree.h>

struct simple_pi_mutex {
    raw_spinlock_t wait_lock;     /* 保护等待者列表 */
    struct rb_root waiters;       /* 按优先级排序的等待者红黑树 */
    struct task_struct *owner;    /* 当前持有者 */
    int saved_prio;               /* 持有者的原始优先级 */
};

struct pi_waiter {
    struct rb_node node;
    struct task_struct *task;
    int prio;
};

static void pi_mutex_init(struct simple_pi_mutex *lock) {
    raw_spin_lock_init(&lock->wait_lock);
    lock->waiters = RB_ROOT;
    lock->owner = NULL;
}

/* 将等待者插入红黑树（按优先级排序）*/
static void enqueue_waiter(struct simple_pi_mutex *lock, struct pi_waiter *w) {
    struct rb_node **link = &lock->waiters.rb_node, *parent = NULL;
    while (*link) {
        struct pi_waiter *entry = rb_entry(*link, struct pi_waiter, node);
        parent = *link;
        if (w->prio < entry->prio) link = &(*link)->rb_left;
        else link = &(*link)->rb_right;
    }
    rb_link_node(&w->node, parent, link);
    rb_insert_color(&w->node, &lock->waiters);
}

/* PI提升：提升持有者优先级 */
static void pi_boost(struct task_struct *owner, int waiter_prio) {
    if (owner->prio > waiter_prio) {
        /* 保存原优先级 */
        struct simple_pi_mutex *lock = /* owner's held lock */;
        lock->saved_prio = owner->prio;
        /* 提升优先级 */
        owner->prio = waiter_prio;
        /* 重新入队到调度器运行队列 */
        /* rt_mutex_setprio(owner, waiter_prio) */
    }
}

/* 获取锁 */
static int pi_mutex_lock(struct simple_pi_mutex *lock) {
    raw_spin_lock(&lock->wait_lock);
    if (!lock->owner) {
        lock->owner = current;
        raw_spin_unlock(&lock->wait_lock);
        return 0;
    }
    /* 需要等待 */
    struct pi_waiter waiter = { .task = current, .prio = current->prio };
    enqueue_waiter(lock, &waiter);
    /* PI提升持有者 */
    pi_boost(lock->owner, current->prio);
    /* 睡眠 */
    set_current_state(TASK_UNINTERRUPTIBLE);
    raw_spin_unlock(&lock->wait_lock);
    schedule();
    /* 被唤醒后获取锁 */
    return 0;
}

/* 释放锁 */
static void pi_mutex_unlock(struct simple_pi_mutex *lock) {
    raw_spin_lock(&lock->wait_lock);
    if (!rb_empty_root(&lock->waiters)) {
        /* 获取最高优先级的等待者 */
        struct rb_node *first = rb_first(&lock->waiters);
        struct pi_waiter *top = rb_entry(first, struct pi_waiter, node);
        rb_erase(first, &lock->waiters);
        lock->owner = top->task;
        /* 恢复原优先级 */
        current->prio = lock->saved_prio;
        /* 唤醒等待者 */
        wake_up_process(top->task);
    } else {
        lock->owner = NULL;
    }
    raw_spin_unlock(&lock->wait_lock);
}
```

核心PI协议：(1)等待者按优先级排序。(2)最高优先级等待者的优先级提升给持有者。(3)释放时唤醒最高优先级等待者并恢复优先级。

Here's a complete C program demonstrating io_uring for asynchronous file I/O. This example reads a file using io_uring's submission/completion queue model.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/mman.h>
#include <linux/io_uring.h>
#include <sys/syscall.h>

// io_uring syscall wrappers
static int io_uring_setup(unsigned entries, struct io_uring_params *p) {
    return syscall(__NR_io_uring_setup, entries, p);
}

static int io_uring_enter(int fd, unsigned to_submit, unsigned min_complete,
                          unsigned flags, void *sig) {
    return syscall(__NR_io_uring_enter, fd, to_submit, min_complete,
                   flags, sig, 0);
}

struct ring_state {
    int ring_fd;
    unsigned *sq_head, *sq_tail, *sq_ring_mask, *sq_ring_entries;
    unsigned *sq_flags, *sq_array;
    unsigned *cq_head, *cq_tail, *cq_ring_mask, *cq_ring_entries;
    struct io_uring_cqe *cqes;
    struct io_uring_sqe *sqes;
};

int setup_ring(unsigned entries, struct ring_state *rs) {
    struct io_uring_params p = {0};

    rs->ring_fd = io_uring_setup(entries, &p);
    if (rs->ring_fd < 0) { perror("io_uring_setup"); return -1; }

    // Map SQ ring
    void *sq_ring = mmap(0, p.sq_off.array + p.sq_entries * sizeof(unsigned),
        PROT_READ | PROT_WRITE, MAP_SHARED | MAP_POPULATE,
        rs->ring_fd, IORING_OFF_SQ_RING);

    rs->sq_head = sq_ring + p.sq_off.head;
    rs->sq_tail = sq_ring + p.sq_off.tail;
    rs->sq_ring_mask = sq_ring + p.sq_off.ring_mask;
    rs->sq_ring_entries = sq_ring + p.sq_off.ring_entries;
    rs->sq_flags = sq_ring + p.sq_off.flags;
    rs->sq_array = sq_ring + p.sq_off.array;

    // Map SQE array
    rs->sqes = mmap(0, p.sq_entries * sizeof(struct io_uring_sqe),
        PROT_READ | PROT_WRITE, MAP_SHARED | MAP_POPULATE,
        rs->ring_fd, IORING_OFF_SQES);

    // Map CQ ring
    void *cq_ring = mmap(0, p.cq_off.cqes + p.cq_entries * sizeof(struct io_uring_cqe),
        PROT_READ | PROT_WRITE, MAP_SHARED | MAP_POPULATE,
        rs->ring_fd, IORING_OFF_CQ_RING);

    rs->cq_head = cq_ring + p.cq_off.head;
    rs->cq_tail = cq_ring + p.cq_off.tail;
    rs->cq_ring_mask = cq_ring + p.cq_off.ring_mask;
    rs->cq_ring_entries = cq_ring + p.cq_off.ring_entries;
    rs->cqes = cq_ring + p.cq_off.cqes;

    return 0;
}

int submit_read(struct ring_state *rs, int fd, void *buf, 
                unsigned len, off_t offset, __u64 user_data) {
    unsigned tail = *rs->sq_tail;
    unsigned index = tail & *rs->sq_ring_mask;

    // Fill SQE
    struct io_uring_sqe *sqe = &rs->sqes[index];
    memset(sqe, 0, sizeof(*sqe));
    sqe->opcode = IORING_OP_READ;
    sqe->fd = fd;
    sqe->addr = (__u64)buf;
    sqe->len = len;
    sqe->off = offset;
    sqe->user_data = user_data;

    // Update SQ array
    rs->sq_array[index] = index;

    // Advance tail
    __atomic_store_n(rs->sq_tail, tail + 1, __ATOMIC_RELEASE);

    return 0;
}

int reap_completions(struct ring_state *rs, int min_complete) {
    // Submit and wait
    int ret = io_uring_enter(rs->ring_fd, 1, min_complete,
        IORING_ENTER_GETEVENTS, NULL);
    if (ret < 0) { perror("io_uring_enter"); return -1; }

    // Process completions
    unsigned head = *rs->cq_head;
    unsigned tail = *rs->cq_tail;

    while (head != tail) {
        unsigned index = head & *rs->cq_ring_mask;
        struct io_uring_cqe *cqe = &rs->cqes[index];

        printf("Read completed: user_data=%llu, result=%d bytes\n",
               cqe->user_data, cqe->res);

        head++;
    }
    __atomic_store_n(rs->cq_head, head, __ATOMIC_RELEASE);

    return head - *rs->cq_head;
}

int main() {
    struct ring_state rs;
    char buf[4096];

    setup_ring(8, &rs);
    int fd = open("/etc/passwd", O_RDONLY);

    submit_read(&rs, fd, buf, sizeof(buf), 0, 42);
    reap_completions(&rs, 1);

    printf("First line: %s\n", buf);
    close(fd);
    return 0;
}
```

**Key Concepts**:
1. `io_uring_setup()` creates the ring and returns an FD for mmap
2. Three separate mmap calls map the SQ ring, SQE array, and CQ ring
3. Submission: fill SQE, update SQ array, advance tail
4. `io_uring_enter()` with `IORING_ENTER_GETEVENTS` submits and waits
5. Completion: read CQEs between head and tail, advance head
6. `user_data` is an opaque value passed through for correlation

**For Production**: Use liburing (`#include <liburing.h>`) which provides a cleaner API: `io_uring_queue_init()`, `io_uring_get_sqe()`, `io_uring_submit()`, `io_uring_wait_cqe()`.

```c
/*
 * Analyze THP usage efficiency by comparing actual
 * THP-backed memory with potential THP memory.
 */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef unsigned long ulong;

struct thp_analysis {
    ulong anon_huge_pages_kb;
    ulong anon_pages_kb;
    ulong thp_fault_alloc;
    ulong thp_fault_fallback;
    ulong thp_collapse_alloc;
    ulong thp_collapse_alloc_failed;
    ulong thp_split_page;
    ulong thp_split_page_failed;
};

static int read_meminfo_field(const char *field, ulong *val)
{
    FILE *f = fopen("/proc/meminfo", "r");
    char line[256], name[64];
    while (fgets(line, sizeof(line), f)) {
        if (sscanf(line, "%63s %lu", name, val) == 2) {
            name[strlen(name)-1] = 0; /* remove ':' */
            if (strcmp(name, field) == 0) {
                fclose(f);
                return 0;
            }
        }
    }
    fclose(f);
    return -1;
}

static ulong read_vmstat(const char *field)
{
    FILE *f = fopen("/proc/vmstat", "r");
    char line[256], name[64];
    ulong val = 0;
    while (fgets(line, sizeof(line), f)) {
        if (sscanf(line, "%63s %lu", name, &val) == 2) {
            if (strcmp(name, field) == 0) {
                fclose(f);
                return val;
            }
        }
    }
    fclose(f);
    return 0;
}

int main(void) {
    struct thp_analysis a;
    double fault_success, collapse_success, split_rate;
    double thp_coverage;

    read_meminfo_field("AnonHugePages", &a.anon_huge_pages_kb);
    read_meminfo_field("AnonPages", &a.anon_pages_kb);
    a.thp_fault_alloc = read_vmstat("thp_fault_alloc");
    a.thp_fault_fallback = read_vmstat("thp_fault_fallback");
    a.thp_collapse_alloc = read_vmstat("thp_collapse_alloc");
    a.thp_collapse_alloc_failed =
        read_vmstat("thp_collapse_alloc_failed");
    a.thp_split_page = read_vmstat("thp_split_page");

    printf("=== THP Analysis ===\n\n");

    /* THP coverage: % of anonymous memory backed by THP */
    if (a.anon_pages_kb > 0) {
        thp_coverage = 100.0 * a.anon_huge_pages_kb /
                       a.anon_pages_kb;
        printf("THP coverage: %.1f%% (%lu MB of %lu MB "
               "anonymous memory)\n",
               thp_coverage,
               a.anon_huge_pages_kb / 1024,
               a.anon_pages_kb / 1024);
    }

    /* Fault allocation success rate */
    ulong total_faults = a.thp_fault_alloc +
                          a.thp_fault_fallback;
    if (total_faults > 0) {
        fault_success = 100.0 * a.thp_fault_alloc /
                        total_faults;
        printf("THP fault success rate: %.1f%% "
               "(%lu alloc, %lu fallback)\n",
               fault_success,
               a.thp_fault_alloc, a.thp_fault_fallback);
    }

    /* Collapse success rate */
    ulong total_collapse = a.thp_collapse_alloc +
                            a.thp_collapse_alloc_failed;
    if (total_collapse > 0) {
        collapse_success = 100.0 * a.thp_collapse_alloc /
                           total_collapse;
        printf("THP collapse success rate: %.1f%% "
               "(%lu alloc, %lu failed)\n",
               collapse_success,
               a.thp_collapse_alloc,
               a.thp_collapse_alloc_failed);
    }

    /* Split rate indicator */
    printf("THP splits: %lu (high value indicates "
           "THP instability)\n", a.thp_split_page);

    /*
     * Interpretation:
     * - Coverage < 20%: THP is not effective. Check defrag
     *   setting and compaction status.
     * - Fault fallback > 50%: Memory fragmentation is
     *   preventing THP allocation. Consider increasing
     *   min_free_kbytes or running compaction.
     * - High split rate: THPs are being split frequently,
     *   indicating COW, mprotect, or munmap on huge pages.
     *   Consider MADV_NOHUGEPAGE for affected regions.
     */

    return 0;
}
```
此工具通过/proc/meminfo和/proc/vmstat的数据分析THP效率。关键指标：THP coverage（匿名内存中THP占比）反映THP的实际使用量；fault fallback rate反映内存碎片化程度；split rate反映THP的稳定性。结合这些信息可以优化THP配置。

RCU relies on the scheduler to report quiescent states that drive grace period advancement. This interaction is carefully designed to minimize overhead.

**Quiescent state reporting points**:
```c
/* 1. Context switch (schedule) */
static void __schedule(void) {
    /* ... */
    rcu_note_context_switch(preempt);  /* Report QS to RCU */
    /* ... */
}

/* 2. Return to userspace */
static void exit_to_user_mode(void) {
    rcu_user_enter();  /* Report QS — leaving kernel */
}

/* 3. Idle entry */
static void do_idle(void) {
    rcu_idle_enter();  /* Report QS — entering idle */
}
```

**rcu_note_context_switch implementation**:
```c
void rcu_note_context_switch(bool preempt) {
    struct rcu_data *rdp = this_cpu_ptr(&rcu_data);
    /* Mark that this CPU has passed through a quiescent state */
    rdp->core_needs_qs = false;
    /* If this was the last CPU needed for the current GP,
     * advance the grace period */
    rcu_report_qs_rdp(rdp);
}
```

**Scheduler tick RCU processing**:
```c
void scheduler_tick(void) {
    /* Called from timer interrupt on each tick */
    rcu_sched_clock_irq(user_tick);
    /* Check if RCU needs a quiescent state from this CPU */
    if (rdp->core_needs_qs) {
        /* Force a quiescent state report */
        rcu_report_qs_rdp(rdp);
    }
    /* Check for expedited GP — may send IPI */
    rcu_flavor_check_callbacks(user_tick);
}
```

**Preemptible RCU interaction**:
```c
/* In preemptible RCU, context switch must check nesting */
void rcu_preempt_note_context_switch(void) {
    if (current->rcu_read_lock_nesting > 0) {
        /* Task is in an RCU read-side critical section!
         * Must report this to RCU — it cannot be a QS */
        rcu_preempt_ctxt_queue(rnp, rdp);
    }
}
```

**RCU stall detection**: If a CPU doesn't report a quiescent state for too long (default 21 seconds), RCU reports a stall warning, often indicating a bug where code is spinning without calling cond_resched() or schedule().

The seqlock implementation relies on carefully placed memory barriers to ensure data consistency.

```c
/* Writer begin */
static inline void write_seqcount_begin(seqcount_t *s) {
    s->sequence++;       /* Odd = write in progress */
    smp_wmb();           /* Ensure sequence update visible BEFORE data writes */
    /* Without this barrier, a reader might see stale sequence but new data */
}

/* Writer end */
static inline void write_seqcount_end(seqcount_t *s) {
    smp_wmb();           /* Ensure data writes complete BEFORE sequence update */
    s->sequence++;       /* Even = stable */
    /* Without this barrier, a reader might see new sequence but old data */
}

/* Reader begin */
static inline unsigned read_seqcount_begin(seqcount_t *s) {
    unsigned ret;
    while ((ret = READ_ONCE(s->sequence)) & 1)
        cpu_relax();     /* Writer active — spin */
    smp_rmb();           /* Ensure sequence read happens BEFORE data reads */
    return ret;
}

/* Reader retry check */
static inline int read_seqcount_retry(seqcount_t *s, unsigned start) {
    smp_rmb();           /* Ensure data reads complete BEFORE re-checking sequence */
    return READ_ONCE(s->sequence) != start;
}
```

**Why each barrier is needed**:
1. **Writer begin smp_wmb**: Prevents data writes from being reordered before the odd sequence. Without it, a reader could see odd sequence and retry, missing the actual data update window.
2. **Writer end smp_wmb**: Prevents the even sequence from being written before all data. Without it, a reader could see even sequence but stale data.
3. **Reader begin smp_rmb**: Prevents data reads from being hoisted before the sequence check.
4. **Reader retry smp_rmb**: Prevents the sequence recheck from being moved before data reads.

On x86 (TSO), smp_wmb and smp_rmb are often no-ops, making seqlocks nearly free. On ARM64, each barrier costs ~30 cycles.

缺页异常（Page Fault）是当进程访问一个虚拟地址但该地址没有有效的物理页面映射或访问权限不足时，CPU产生的异常（x86上是第14号异常）。Linux内核的缺页异常处理是虚拟内存管理的核心机制。

**缺页异常的类型：**

1. **次要缺页异常（Minor Fault）**：所需页面已在内存中，但页表项（PTE）尚未建立或权限不足。
   - 匿名页面的首次访问：分配一个零页面或新物理页面
   - Copy-on-Write（写时复制）：fork()后子进程写共享页面时，分配新页面并复制内容
   - 页面缓存命中：文件页面已在page cache中

2. **主要缺页异常（Major Fault）**：所需页面不在内存中，需要从磁盘读取。
   - 从交换分区读回被换出的页面
   - 从文件系统读取未加载的页面
   - 涉及磁盘I/O，延迟在毫秒级别

3. **无效缺页异常**：进程访问未映射的地址或权限不足的地址，导致SIGSEGV信号。

**处理流程（do_user_addr_fault）：**

```c
// 简化版处理流程
static void do_user_addr_fault(struct pt_regs *regs,
                                unsigned long error_code,
                                unsigned long address)
{
    struct vm_area_struct *vma;
    vm_fault_t fault;

    // 1. 查找VMA
    vma = find_vma(mm, address);
    if (!vma || vma->vm_start > address) {
        // 检查是否是栈扩展
        if (expand_stack(vma, address))
            goto bad_area; // 发送SIGSEGV
    }

    // 2. 检查权限
    if (!(vma->vm_flags & (VM_READ | VM_WRITE | VM_EXEC)))
        goto bad_area;

    // 3. 处理缺页
    fault = handle_mm_fault(vma, address, flags);

    if (fault & VM_FAULT_MAJOR)
        current->majflt++;
    else
        current->minflt++;
}
```

**handle_mm_fault()的详细处理：**

1. **PTE不存在（demand paging）**：
   - 匿名映射：调用do_anonymous_page()，从伙伴系统分配一个页面或映射到零页面（zero page），建立PTE
   - 文件映射：调用do_fault()→文件系统的fault操作，从磁盘读取页面到page cache，然后建立PTE

2. **PTE存在但只读（写时复制）**：
   - 调用do_wp_page()：分配新页面→复制内容→更新PTE为可写
   - 这是fork()后写共享页面的核心机制

3. **页面在swap中**：
   - 调用do_swap_page()：从swap设备读取页面到内存→更新PTE→从swap cache中移除

**内核缺页异常的特殊处理：**
内核态的缺页异常由do_kern_addr_fault()处理。如果内核访问用户空间地址（如copy_from_user/copy_to_user），异常表中（exception table）有对应的修复条目（fixup），将执行流跳转到错误处理代码，返回-EFAULT给系统调用。

```c
// exception table 示例
// copy_from_user中的__copy_from_user_inatomic()使用
asm volatile("1: rep movsb\n"
             "2:\n"
             ".section .fixup\n"
             "3: movq %1, %0; jmp 2b\n"
             ".previous\n"
             ".section __ex_table\n"
             ".quad 1b, 3b\n"
             ".previous");
```

**性能影响：**
主要缺页异常是性能杀手，因为它涉及磁盘I/O。对于性能敏感的应用程序，可以使用mlock()锁定页面防止换出，或使用MAP_POPULATE预加载所有页面来避免主要缺页异常。

The `dup()`, `dup2()`, and `dup3()` system calls create a copy of an existing file descriptor, where both the original and new descriptor refer to the same open file description (the same `struct file` in the kernel).

**System Call Numbers (x86_64)**:
- `dup` = 32
- `dup2` = 33
- `dup3` = 292

**Kernel Implementation**:

```c
SYSCALL_DEFINE1(dup, unsigned int, fildes) {
    int ret = -EBADF;
    struct file *file = fget(fildes);
    if (file) {
        ret = get_unused_fd_flags(0);
        if (ret >= 0)
            fd_install(ret, file);
        else
            fput(file);
    }
    return ret;
}
```

**dup()**: Allocates the lowest-numbered unused file descriptor that refers to the same `struct file` as the original. The new FD shares the file offset, status flags, and file description with the original.

**dup2(oldfd, newfd)**: Makes `newfd` a copy of `oldfd`. If `newfd` was already open, it is silently closed first. If `oldfd == newfd`, the call does nothing and returns `newfd`. The implementation:

```c
SYSCALL_DEFINE2(dup2, unsigned int, oldfd, unsigned int, newfd) {
    return ksys_dup3(oldfd, newfd, 0);
}
```

**dup3(oldfd, newfd, flags)**: Like `dup2()` but with two differences: (1) it fails with `-EINVAL` if `oldfd == newfd`, and (2) it accepts the `O_CLOEXEC` flag, which atomically sets the close-on-exec flag on the new descriptor.

**Internal Mechanism**: The core function is `ksys_dup3()`:
```c
static int ksys_dup3(unsigned int oldfd, unsigned int newfd, int flags) {
    struct file *oldfile = fget(oldfd);
    // Validate oldfd is valid
    // Check newfd is in range [0, rlimit(RLIMIT_NOFILE))
    // If newfd is open, close it via filp_close()
    // get_file(oldfile) - increment reference count
    // fd_install(newfd, oldfile)
    // Set O_CLOEXEC if requested
}
```

**Reference Counting**: The `struct file` has an atomic reference count (`f_count`). When `dup()` creates a new FD pointing to the same file, `get_file()` increments `f_count`. Each `close()` call decrements it. The file's resources are only freed when the count reaches zero.

**Use Cases**:
1. **I/O Redirection**: Shell pipelines use `dup2()` to redirect stdin/stdout/stderr before `exec()`.
2. **Socket Passing**: Server processes `dup()` accepted sockets to worker threads.
3. **Saving and Restoring**: Save stdout with `dup(1)`, redirect to a file, then restore with `dup2(saved_fd, 1)`.

**Atomicity**: `dup3()` with `O_CLOEXEC` is atomic — there is no window where the FD exists without the close-on-exec flag. This is important in multithreaded programs where another thread might call `fork()` + `exec()` between `dup2()` and a subsequent `fcntl(F_SETFD)`.

**Shared State**: Since both FDs share the same `struct file`:
- They share the file offset (`f_pos`): seeking on one affects the other
- They share file status flags (`f_flags`): changing O_NONBLOCK on one affects the other
- They share file locks: closing one FD does NOT release locks if another FD refers to the same file description

The vm_operations_struct defines a set of callbacks that the kernel invokes for operations on a specific virtual memory area (VMA). It is the mechanism by which filesystems, device drivers, and other kernel subsystems customize the behavior of memory-mapped regions.

**Structure definition:**
```c
struct vm_operations_struct {
    const char *name;
    // Called on page fault within this VMA
    vm_fault_t (*fault)(struct vm_fault *vmf);
    // Called on write to a shared mapping
    vm_fault_t (*page_mkwrite)(struct vm_fault *vmf);
    // Called on access via get_user_pages()
    vm_fault_t (*pfn_mkwrite)(struct vm_fault *vmf);
    // Called when VMA is opened (mmap or fork)
    void (*open)(struct vm_area_struct *vma);
    // Called when VMA is closed (munmap or exit)
    void (*close)(struct vm_area_struct *vma);
    // For MAP_SHARED write notifications
    vm_fault_t (*map_pages)(struct vm_fault *vmf, unsigned long start, unsigned long end);
};
```

**How it's set up:**
When mmap() is called on a file, the filesystem's file_operations.mmap callback sets vma->vm_ops:
```c
// ext4 example
static int ext4_file_mmap(struct file *file, struct vm_area_struct *vma)
{
    vma->vm_ops = &ext4_file_vm_ops;
    // ...
}

static const struct vm_operations_struct ext4_file_vm_ops = {
    .fault     = ext4_filemap_fault,
    .map_pages = filemap_map_pages,
    .page_mkwrite = ext4_page_mkwrite,
};
```

**The fault() callback in detail:**

When a page fault occurs in a file-backed VMA:
1. handle_mm_fault() → do_fault() → __do_fault()
2. __do_fault() calls vma->vm_ops->fault(vmf)
3. The fault callback must:
   - Locate the page in the page cache or read it from disk
   - Store the page in vmf->page
   - Return 0 on success, VM_FAULT_NOPAGE, VM_FAULT_SIGBUS, or VM_FAULT_OOM

**ext4_filemap_fault() implementation:**
```c
static vm_fault_t ext4_filemap_fault(struct vm_fault *vmf)
{
    // Delegate to the generic filemap_fault()
    return filemap_fault(vmf);
}

vm_fault_t filemap_fault(struct vm_fault *vmf)
{
    struct address_space *mapping = vmf->vma->vm_file->f_mapping;
    pgoff_t offset = vmf->pgoff;
    struct page *page;

    // 1. Try to find the page in the page cache
    page = find_get_page(mapping, offset);

    if (page) {
        // Page is in cache - check if up-to-date
        if (PageUptodate(page))
            goto out;  // Return cached page
    } else {
        // Page not in cache - read from disk
        page = pagecache_get_page(mapping, offset, FGP_CREAT | FGP_FOR_MMAP);
        if (!page)
            return VM_FAULT_OOM;

        if (!PageUptodate(page)) {
            // Submit read I/O
            error = mapping->a_ops->readpage(vmf->vma->vm_file, page);
            lock_page(page);
            if (!PageUptodate(page)) {
                unlock_page(page);
                put_page(page);
                return VM_FAULT_SIGBUS;
            }
        }
    }

out:
    vmf->page = page;
    return 0;  // Success - caller will install PTE
}
```

**The map_pages() callback:**
filemap_map_pages() is an optimization that maps multiple pages at once during a page fault, instead of just the faulting page. This reduces the number of faults for sequential access patterns:
```c
vm_fault_t filemap_map_pages(struct vm_fault *vmf,
                              unsigned long start_pgoff, unsigned long end_pgoff)
{
    // Iterate over pages in the range
    xas_for_each(&xas, page, end_pgoff) {
        // Map each up-to-date page
        do_set_pte(vmf, page, addr, &pte, false, false);
    }
}
```

**page_mkwrite() callback:**
Called when a process writes to a MAP_SHARED file mapping. The filesystem uses this to:
- Allocate disk blocks for the page (delayed allocation)
- Mark the page dirty for writeback
- ext4_page_mkwrite() calls ext4_block_write_begin() to prepare the page for writing

**Device driver usage:**
Device drivers set custom vm_ops for mmap'd device memory:
```c
static const struct vm_operations_struct my_driver_vm_ops = {
    .fault = my_driver_fault,  // Maps device memory pages
    .open = my_driver_vma_open,
    .close = my_driver_vma_close,
};
```

Ordered workqueues guarantee that work items execute one at a time in submission order. Created with `alloc_ordered_workqueue(name, flags)` which internally sets `max_active = 1`. This means only one worker thread processes items from the queue at any time. Implementation: 1) The workqueue's `max_active` is 1, so only one work item can be in-flight. 2) When a work item completes, the worker picks the next item from the pending list (FIFO). 3) `WQ_UNBOUND` can be combined with `max_active=1` for an ordered unbound workqueue that can run on any CPU but still processes items sequentially. Use cases: serializing hardware access (SPI, I2C transactions), ensuring ordered event processing, maintaining data consistency. Example:
```c
struct workqueue_struct *wq = alloc_ordered_workqueue("serial_wq", 0);
queue_work(wq, &work1); // Always runs before work2
queue_work(wq, &work2);
```

Memory barriers enforce ordering constraints on memory operations and are fundamental to concurrent code correctness on SMP systems.

Types of memory barriers:
```c
smp_mb();   /* Full memory barrier */
smp_rmb();  /* Read (acquire) barrier */
smp_wmb();  /* Write (release) barrier */
barrier();  /* Compiler barrier only */
```

Locking semantics and memory barriers: Lock acquisition provides acquire semantics — all memory operations after lock() happen after the lock. Lock release provides release semantics — all operations before unlock() happen before release.

Architecture implementations:

| Architecture | smp_mb() | smp_rmb() | smp_wmb() |
|-------------|-----------|-----------|------------|
| x86 (TSO) | MFENCE | often no-op | often no-op |
| ARM64 | DMB ISH | DMB ISHLD | DMB ISHST |
| PowerPC | sync | lwsync | lwsync |

Common patterns requiring explicit barriers:
```c
/* Flag-based synchronization */
shared_data = compute_value();
smp_wmb();
WRITE_ONCE(data_ready, 1);

/* Consumer */
if (READ_ONCE(data_ready)) {
    smp_rmb();
    use(shared_data);
}
```

Relationship to atomic operations: atomic_add_return() = full barrier, _acquire = acquire, _release = release, _relaxed = no barrier.

When NOT to use barriers: Prefer locks, RCU, or atomic operations over raw barriers. Raw barriers are error-prone.

`msi_domain`是专门为MSI/MSI-X中断设计的IRQ域（`irq_domain`），提供MSI向量到Linux IRQ号的映射。

核心功能：1) **分配**：`msi_domain_alloc_irqs()`为设备的MSI向量分配IRQ描述符和中断资源。
2) **消息组合**：通过`msi_domain_ops->msi_init()`和`irq_chip->irq_compose_msi_msg()`生成MSI消息。
3) **层次结构**：MSI域通常是子域，父域是中断控制器域（如APIC域）。`irq_data->parent_data`链接到父域。

MSI域层次：设备 → MSI域 → APIC域 → CPU

```c
struct msi_domain_ops {
    irq_hw_number_t (*get_hwirq)(...);
    int (*msi_init)(...);
    void (*msi_free)(...);
    void (*msi_prepare)(...);
};
```

MSI域通过`platform_msi_create_irq_domain()`或`pci_msi_create_irq_domain()`创建。

在内存cgroup中，refault机制跟踪被回收的页面重新被访问的频率，用于评估回收策略的有效性。

工作原理：
1. 当页面从cgroup的LRU链表中回收时，内核在shadow节点中记录回收时间戳
2. 当相同文件偏移量的页面再次被访问时（refault），内核检查shadow节点
3. 如果refault发生得太快（working set大于可用内存），增加该类型页面的扫描成本
4. 高refault率意味着回收过于激进，内核会减少该类页面的回收

```c
void workingset_refault(struct folio *folio, void *shadow)
{
    // 计算自回收以来的时间
    refault_distance = workingset_eviction_time - current_time;

    // 如果距离太短，说明working set > available memory
    if (refault_distance < refault_threshold) {
        // 标记为working set refault
        // 增加活跃列表的大小
        activate_page(folio);
    }
}
```

这个机制确保重要的文件缓存不会被过度回收，即使在内存cgroup接近限制时也是如此。

static int my_probe(struct usb_interface *iface, const struct usb_device_id *id) {
    struct my_priv *priv = devm_kzalloc(&iface->dev, sizeof(*priv), GFP_KERNEL);
    priv->udev = usb_get_dev(interface_to_usbdev(iface));
    struct usb_endpoint_descriptor *ep;
    for (int i = 0; i < iface->cur_altsetting->desc.bNumEndpoints; i++) {
        ep = &iface->cur_altsetting->endpoint[i].desc;
        if (usb_endpoint_is_bulk_in(ep)) {
            priv->pipe = usb_rcvbulkpipe(priv->udev, ep->bEndpointAddress);
            break;
        }
    }
    priv->urb = usb_alloc_urb(0, GFP_KERNEL);
    usb_fill_bulk_urb(priv->urb, priv->udev, priv->pipe, buf, 512, cb, priv);
    usb_submit_urb(priv->urb, GFP_KERNEL);
    return 0;
}

Tasklets and workqueues have fundamentally different locking requirements due to their execution contexts.

**Tasklets (softirq context)**:
```c
/* Tasklets run in softirq context — cannot sleep */
struct tasklet_struct {
    unsigned long data;
    void (*func)(unsigned long);
    unsigned long state;  /* Atomic state bits */
};

/* Tasklet locking — only spinlocks allowed */
static DEFINE_SPINLOCK(tasklet_data_lock);

static void my_tasklet_func(unsigned long data) {
    spin_lock(&tasklet_data_lock);  /* OK — spinlock */
    process_data();
    spin_unlock(&tasklet_data_lock);

    /* WRONG: Cannot use mutex in tasklet */
    /* mutex_lock(&m); BUG: might sleep */
}

/* Tasklet scheduling uses atomic bitops — lock-free */
static inline void tasklet_schedule(struct tasklet_struct *t) {
    if (!test_and_set_bit(TASKLET_STATE_SCHED, &t->state)) {
        /* Add to per-CPU tasklet list — no lock needed */
        __tasklet_schedule(t);
    }
}
```

**Workqueues (process context)**:
```c
/* Workqueue handlers run in kernel thread — can sleep */
static void my_work_func(struct work_struct *work) {
    /* Can use ANY locking primitive */
    mutex_lock(&my_mutex);         /* OK — can sleep */
    data = kmalloc(size, GFP_KERNEL); /* OK — can sleep */
    down_read(&my_rwsem);          /* OK — can sleep */
    mutex_unlock(&my_mutex);
}
```

**Shared data between tasklet and workqueue**:
```c
/* Data shared between tasklet (softirq) and workqueue (process) */
spinlock_t shared_lock;

/* Tasklet side */
void tasklet_handler(unsigned long data) {
    spin_lock(&shared_lock);     /* Disable softirq on this CPU */
    update_shared();
    spin_unlock(&shared_lock);
}

/* Workqueue side */
void work_handler(struct work_struct *work) {
    spin_lock_bh(&shared_lock);  /* Disable softirq to prevent tasklet */
    read_shared();
    spin_unlock_bh(&shared_lock);
}
```

**Locking comparison**:

| Context | Spinlock | Mutex | Rwsem | Semaphore |
|---------|----------|-------|-------|-----------|
| Tasklet | Yes | NO | NO | NO |
| Workqueue | Yes | Yes | Yes | Yes |
| Tasklet-Workqueue shared | spin_lock_bh needed | N/A | N/A | N/A |

**Decision guide**: Use tasklets when you need minimal latency and the handler is short (can use only spinlocks). Use workqueues when the handler needs to sleep or do complex operations.

Adaptive spinning in kernel mutexes means the mutex dynamically decides whether to spin or sleep based on runtime conditions. The implementation varies by architecture.

**Core adaptive logic** (kernel/locking/mutex.c):
```c
static bool mutex_optimistic_spin(struct mutex *lock, struct mutex_waiter *waiter) {
    struct task_struct *owner;
    while (true) {
        owner = READ_ONCE(lock->owner);
        if (!owner) return true;       /* Lock free — try to acquire */
        if (!owner->on_cpu) return false; /* Owner sleeping — spinning futile */
        if (need_resched()) return false; /* Need to yield CPU */

        /* Architecture-specific backoff */
        cpu_relax();

        /* ARM64: May use WFE (Wait For Event) to reduce power */
        /* x86: PAUSE instruction */
        /* PowerPC: May yield thread timeslice */
    }
}
```

**Architecture-specific optimizations**:
- **x86**: PAUSE instruction reduces pipeline power and avoids memory ordering issues. Hyperthreaded cores benefit from PAUSE releasing execution resources.
- **ARM64**: May use WFE (Wait For Event) which puts the core in a low-power state until an event (SEV) is sent by the lock releaser. This is more power-efficient than a tight spin loop.
- **PowerPC**: Thread priority hints can lower the spinner's thread priority, giving more resources to the lock holder.

**Adaptive threshold**: Modern kernels track how long spinning has been attempted. If spinning exceeds a threshold (typically a few microseconds), the waiter gives up and sleeps — converting to traditional blocking behavior.

The adaptive approach provides the best of both worlds: spinlock-like performance for short contentions, mutex-like behavior for long contentions.

CPU hotplug allows adding or removing CPUs at runtime. The scheduler must migrate tasks away from offline CPUs and handle runqueue state. Implementation spans `kernel/cpu.c`, `kernel/sched/core.c`, and architecture-specific code.

**Offline sequence** (`cpu_down()` in `kernel/cpu.c`):
1. `__cpu_down()` takes the `cpu_hotplug_lock`
2. Calls `cpuhp_invoke_callback()` for each hotplug state
3. The scheduler-specific callback is `sched_cpu_deactivate()`:
   - Sets the CPU offline in the scheduler: `set_cpu_active(cpu, false)`
   - Calls `sched_idle_force_rq()` to force all tasks off the CPU
   - `migrate_tasks()` moves all tasks from the dying CPU's runqueue to other CPUs

**migrate_tasks()** in `kernel/sched/core.c`:
```c
static void migrate_tasks(struct rq *dead_rq, struct rq_flags *rf) {
    struct rq *rq = dead_rq;
    struct task_struct *next, *stop = rq->stop;
    // Use the stop task to do the migration
    // Iterate all tasks on the runqueue and move them
    while ((next = pick_next_task(rq, ...))) {
        if (next == stop) continue;
        // Select a destination CPU
        dest_cpu = select_fallback_rq(dead_rq->cpu, next);
        // Move the task
        __migrate_task(rq, next, dest_cpu);
    }
}
```

**Fallback CPU selection**: `select_fallback_rq()` finds a valid destination CPU considering:
- `cpus_allowed` (task's CPU affinity)
- Online CPUs
- NUMA topology preferences

**Online sequence**: `cpu_up()` → `sched_cpu_activate()` → rebuilds scheduling domains and enables the CPU for scheduling.

**Scheduling domain rebuild**: `partition_sched_domains()` is called during hotplug to rebuild the scheduling domain hierarchy. CPUs that go offline are removed from their domains; CPUs that come online are added.

**Stop machine**: `stop_machine()` uses the `stop_sched_class` to run a function on all CPUs simultaneously. This is used during critical hotplug operations to ensure atomicity.

**Watchdog and per-CPU threads**: Per-CPU kernel threads (kworker, ksoftirqd, migration) are stopped and restarted during hotplug via hotplug state callbacks.

**Interaction with cgroups**: When a CPU goes offline, cpuset controllers may need to update their `cpus_allowed` masks. `cpuset_hotplug_workfn()` handles this asynchronously.

MOK是shim的MokManager管理的用户注册密钥。用户可以通过启动时的MOK注册界面注册自己的签名密钥（如自定义内核模块或内核）。注册的MOK存储在EFI变量中并被shim信任用于签名验证。允许Secure Boot系统信任用户签名代码而无需Microsoft签名服务。mokutil是管理MOK的用户空间工具。 Memory barrier usage in a producer-consumer ring buffer:
```c
struct ring_buffer {
    volatile unsigned int head;
    volatile unsigned int tail;
    char data[RING_SIZE];
};

/* Producer writes data then updates tail */
void producer(struct ring_buffer *rb, const void *buf, unsigned len)
{
    unsigned int tail = READ_ONCE(rb->tail);
    memcpy(rb->data + (tail & RING_MASK), buf, len);
    smp_wmb();  /* Ensure data is written before tail update */
    WRITE_ONCE(rb->tail, tail + len);
}

/* Consumer reads tail then reads data */
int consumer(struct ring_buffer *rb, void *buf, unsigned len)
{
    unsigned int head = READ_ONCE(rb->head);
    unsigned int tail = READ_ONCE(rb->tail);
    smp_rmb();  /* Ensure tail is read before data */
    if (tail - head < len)
        return -EAGAIN;
    memcpy(buf, rb->data + (head & RING_MASK), len);
    smp_wmb();  /* Ensure data read completes before head update */
    WRITE_ONCE(rb->head, head + len);
    return 0;
}
```

ACPI states: S0 (active), S1-S3 (sleep), S4 (hibernate), S5 (off). S3 (Suspend-to-RAM) most common. Suspend: freeze processes, suspend devices (driver callbacks), execute _PTS/_GTS AML methods, disable interrupts, write sleep state to PM1a_CNT/PM1b_CNT (from FADT). Wake on events (lid, keyboard, RTC). Resume: re-enable interrupts, _WAK method, resume devices, thaw processes. CONFIG_SUSPEND, CONFIG_HIBERNATION, CONFIG_PM_SLEEP. Kernel module with proper error handling using goto cleanup:
```c
static int __init my_driver_probe(struct platform_device *pdev)
{
    struct my_priv *priv;
    struct resource *res;
    int ret;

    priv = devm_kzalloc(&pdev->dev, sizeof(*priv), GFP_KERNEL);
    if (!priv)
        return -ENOMEM;

    res = platform_get_resource(pdev, IORESOURCE_MEM, 0);
    priv->base = devm_ioremap_resource(&pdev->dev, res);
    if (IS_ERR(priv->base))
        return PTR_ERR(priv->base);

    priv->clk = devm_clk_get(&pdev->dev, NULL);
    if (IS_ERR(priv->clk))
        return PTR_ERR(priv->clk);

    ret = clk_prepare_enable(priv->clk);
    if (ret)
        return ret;

    priv->irq = platform_get_irq(pdev, 0);
    if (priv->irq < 0) {
        ret = priv->irq;
        goto err_clk;
    }

    ret = devm_request_irq(&pdev->dev, priv->irq, my_isr,
                           IRQF_SHARED, "my_dev", priv);
    if (ret)
        goto err_clk;

    platform_set_drvdata(pdev, priv);
    return 0;

err_clk:
    clk_disable_unprepare(priv->clk);
    return ret;
}
```

```c
#include <linux/vmalloc.h>
#include <linux/string.h>

/*
 * Allocate a large buffer using vmalloc and initialize it.
 * vmalloc is appropriate here because the buffer is large
 * (>PAGE_SIZE) and doesn't need physical contiguity.
 */
static void *create_large_buffer(size_t size)
{
    void *buf;

    /*
     * vmalloc allocates virtually contiguous memory from
     * the vmalloc area. Pages may be physically scattered.
     * vzalloc additionally zeroes the memory (__GFP_ZERO).
     */
    buf = vzalloc(size);
    if (!buf)
        return NULL;

    /*
     * Verify the allocation by writing to each page.
     * This forces physical page allocation if lazy alloc
     * is in effect (some architectures).
     */
    for (size_t off = 0; off < size; off += PAGE_SIZE) {
        /* Touch each page to ensure it's faulted in */
        ((volatile char *)buf)[off] = 0;
    }

    return buf;
}

/*
 * Alternative: use vmalloc_user for buffers that will be
 * shared with userspace via remap_vmalloc_range().
 */
static void *create_user_shared_buffer(size_t size)
{
    void *buf = vmalloc_user(size);
    if (!buf)
        return NULL;
    return buf;
}

static void destroy_buffer(void *buf)
{
    /* vfree handles NULL safely */
    vfree(buf);
}

/*
 * Note: Do NOT use virt_to_page() on vmalloc addresses —
 * they are not in the direct map. Use vmalloc_to_page()
 * to get the struct page for a vmalloc address.
 */
static void inspect_vmalloc_pages(void *buf, size_t size)
{
    for (size_t off = 0; off < size; off += PAGE_SIZE) {
        struct page *page = vmalloc_to_page(buf + off);
        if (page)
            pr_debug("offset %zu: page pfn=%lu\n",
                     off, page_to_pfn(page));
    }
}
```
Key: vmalloc addresses are in the vmalloc range, not the direct map. Always use vmalloc_to_page() instead of virt_to_page(). Use vfree() to release, never kfree().

以下是一个使用libbpf框架编写的eBPF程序，追踪所有open系统调用并记录调用进程和文件名：

```c
// bpf_prog.c
#include "vmlinux.h"
#include <bpf/bpf_helpers.h>
#include <bpf/bpf_tracing.h>

struct event {
    __u32 pid;
    __u32 uid;
    char comm[16];
    char filename[256];
};

struct {
    __uint(type, BPF_MAP_TYPE_RINGBUF);
    __uint(max_entries, 256 * 1024);
} events SEC(".maps");

SEC("tracepoint/syscalls/sys_enter_openat")
int trace_openat(struct trace_event_raw_sys_enter *ctx) {
    struct event *e;
    e = bpf_ringbuf_reserve(&events, sizeof(*e), 0);
    if (!e) return 0;
    e->pid = bpf_get_current_pid_tgid() >> 32;
    e->uid = bpf_get_current_uid_gid() & 0xFFFFFFFF;
    bpf_get_current_comm(&e->comm, sizeof(e->comm));
    bpf_probe_read_user_str(&e->filename, sizeof(e->filename),
                            (void *)ctx->args[1]);
    bpf_ringbuf_submit(e, 0);
    return 0;
}

char LICENSE[] SEC("license") = "GPL";
```

编译命令：clang -g -O2 -target bpf -c bpf_prog.c -o bpf_prog.o

用户空间程序使用libbpf加载和读取ringbuf数据。这个程序展示了BPF map、tracepoint和ringbuf的基本用法。

```c
#include <linux/fs.h>
#include <linux/pagemap.h>
#include <linux/buffer_head.h>
#include <linux/bio.h>

/*
 * Custom filesystem readpage implementation.
 * Called by filemap_fault() when a page cache miss occurs.
 */
static int myfs_readpage(struct file *file, struct folio *folio)
{
    struct inode *inode = folio->mapping->host;
    struct page *page = &folio->page;
    loff_t offset = page_offset(page);
    struct bio *bio;
    sector_t block;
    int err;

    /*
     * Map the file offset to a physical block on disk.
     * This calls the filesystem's block mapping function
     * (e.g., extent tree lookup for ext4).
     */
    block = myfs_map_block(inode, offset >> inode->i_blkbits);
    if (block == 0) {
        /* Sparse file: hole — fill with zeros */
        folio_zero_segment(folio, 0, PAGE_SIZE);
        folio_mark_uptodate(folio);
        folio_unlock(folio);
        return 0;
    }

    /*
     * Submit a bio to read the block from disk.
     * The bio is directed to the block device that
     * contains the inode's data.
     */
    bio = bio_alloc(inode->i_sb->s_bdev, 1,
                    REQ_OP_READ | REQ_RAHEAD,
                    GFP_KERNEL);
    if (!bio) {
        folio_unlock(folio);
        return -ENOMEM;
    }

    bio->bi_iter.bi_sector = block;
    bio_add_folio(bio, folio, PAGE_SIZE, 0);

    /*
     * Set completion callback. When I/O completes,
     * myfs_read_end_io will:
     * 1. Check for errors
     * 2. Set PageUptodate if successful
     * 3. Unlock the page (waking waiters)
     */
    bio->bi_end_io = myfs_read_end_io;
    bio->bi_private = folio;

    submit_bio(bio);

    /*
     * Return 0 immediately — the page remains locked.
     * The caller (filemap_fault) will wait on the page
     * lock (wait_on_page_locked) until I/O completes
     * and myfs_read_end_io unlocks it.
     */
    return 0;
}

static void myfs_read_end_io(struct bio *bio)
{
    struct folio *folio = bio->bi_private;

    if (bio->bi_status) {
        /* I/O error */
        folio_clear_uptodate(folio);
        folio_set_error(folio);
    } else {
        folio_mark_uptodate(folio);
    }

    folio_unlock(folio);
    bio_put(bio);
}

static const struct address_space_operations myfs_aops = {
    .read_folio  = myfs_readpage,
    .readahead   = myfs_readahead,
    .writepage   = myfs_writepage,
    .write_begin = myfs_write_begin,
    .write_end   = myfs_write_end,
};
```
当page fault触发readpage时，页面处于locked状态。I/O完成后必须unlock页面唤醒等待者。如果I/O成功，设置PageUptodate标志；如果失败，设置PageError。readahead回调用于批量预读，接收readahead_control参数指定预读范围。

A complete I2C temperature sensor driver using regmap and hwmon:

```c
#include <linux/i2c.h>
#include <linux/regmap.h>
#include <linux/hwmon.h>
#include <linux/pm_runtime.h>
#include <linux/module.h>

#define TEMP_REG    0x00
#define CONFIG_REG  0x01
#define THRESH_REG  0x02
#define CHIP_ID_REG 0x0F
#define EXPECTED_ID 0xA5

struct tsens_priv {
    struct regmap *regmap;
    struct device *hwmon_dev;
};

static const struct regmap_config tsens_regmap = {
    .reg_bits = 8,
    .val_bits = 16,
    .val_format_endian = REGMAP_ENDIAN_BIG,
    .max_register = 0x1F,
    .cache_type = REGCACHE_RBTREE,
    .volatile_reg = tsens_volatile,
};

static bool tsens_volatile(struct device *dev, unsigned int reg) {
    return reg == TEMP_REG; /* temperature changes continuously */
}

static umode_t tsens_is_visible(const void *drvdata, enum hwmon_sensor_types type,
                                  u32 attr, int channel) {
    switch (attr) {
    case hwmon_temp_input:  return 0444;
    case hwmon_temp_max:    return 0644;
    default: return 0;
    }
}

static int tsens_read(struct device *dev, enum hwmon_sensor_types type,
                       u32 attr, int channel, long *val) {
    struct tsens_priv *priv = dev_get_drvdata(dev);
    unsigned int raw;
    int ret;

    ret = pm_runtime_resume_and_get(dev);
    if (ret < 0) return ret;

    switch (attr) {
    case hwmon_temp_input:
        ret = regmap_read(priv->regmap, TEMP_REG, &raw);
        *val = (s16)raw * 625 / 10; /* 0.0625 C per LSB, output millidegrees */
        break;
    case hwmon_temp_max:
        ret = regmap_read(priv->regmap, THRESH_REG, &raw);
        *val = (s16)raw * 625 / 10;
        break;
    default:
        ret = -EOPNOTSUPP;
    }
    pm_runtime_mark_last_busy(dev);
    pm_runtime_put_autosuspend(dev);
    return ret;
}

static int tsens_write(struct device *dev, enum hwmon_sensor_types type,
                        u32 attr, int channel, long val) {
    struct tsens_priv *priv = dev_get_drvdata(dev);
    if (attr != hwmon_temp_max) return -EOPNOTSUPP;
    u16 raw = val * 10 / 625;
    return regmap_write(priv->regmap, THRESH_REG, raw);
}

static const struct hwmon_ops tsens_hwmon_ops = {
    .is_visible = tsens_is_visible,
    .read = tsens_read,
    .write = tsens_write,
};

static const struct hwmon_channel_info *tsens_info[] = {
    HWMON_CHANNEL_INFO(temp, "sensor"),
    NULL
};

static const struct hwmon_chip_info tsens_chip = {
    .ops = &tsens_hwmon_ops,
    .info = tsens_info,
};

static int tsens_probe(struct i2c_client *client) {
    struct tsens_priv *priv;
    unsigned int id;
    int ret;

    priv = devm_kzalloc(&client->dev, sizeof(*priv), GFP_KERNEL);
    priv->regmap = devm_regmap_init_i2c(client, &tsens_regmap);
    if (IS_ERR(priv->regmap)) return PTR_ERR(priv->regmap);

    ret = regmap_read(priv->regmap, CHIP_ID_REG, &id);
    if (ret || id != EXPECTED_ID) return -ENODEV;

    pm_runtime_set_autosuspend_delay(&client->dev, 2000);
    pm_runtime_use_autosuspend(&client->dev);
    pm_runtime_enable(&client->dev);

    priv->hwmon_dev = devm_hwmon_device_register_with_info(&client->dev,
        "tsens", priv, &tsens_chip, NULL);
    return PTR_ERR_OR_ZERO(priv->hwmon_dev);
}

static const struct of_device_id tsens_of_match[] = {
    { .compatible = "vendor,tsens100" },
    {}
};
MODULE_DEVICE_TABLE(of, tsens_of_match);

static struct i2c_driver tsens_driver = {
    .driver = { .name = "tsens", .of_match_table = tsens_of_match,
                .pm = pm_ptr(&tsens_pm_ops) },
    .probe_new = tsens_probe,
};
module_i2c_driver(tsens_driver);
```

`devm_regmap_init_i2c()` creates a register cache automatically. `REGCACHE_RBTREE` caches non-volatile registers to reduce bus traffic. The hwmon framework exposes temperature via `/sys/class/hwmon/hwmonX/temp1_input`. Runtime PM autosuspend powers down the sensor after 2 seconds of inactivity.
